[ExtensionOf(formDataFieldStr(VendTable, VendTable, ETGTradeLimitPurchReal))]
internal final class ETGVendTableDS_TradeLimit_Extension
{

}

Method.Source:
public void modified()     
{
    next modified();

    if(ETGACFParameters::find().EnableTradeLimit == NoYes::Yes)
    {
        FormDataObject formDataObject = any2Object(this) as FormDataObject;
        FormDataSource formDataSource = formDataObject.datasource();
        VendTable      vendTable      = formDataSource.cursor();
        this.calculateTradeLimitInVendorCurrency(vendTable);
        if(vendTable.ETGRemainingTradeLimitPurchReal == 0)
        {
            vendTable.ETGRemainingTradeLimitPurchReal = vendTable.ETGTradeLimitPurchReal;
        }

    }
}

private void calculateTradeLimitInVendorCurrency(VendTable vendTable)
{
    CurrencyCode vendorCurrency = vendTable.Currency;
    CurrencyCode companyCurrency = Ledger::accountingCurrency();

    if (!vendorCurrency || !companyCurrency)
    {
        return;
    }

    vendTable.ETGTradeLimitInVendorCurrency = this.convertAmountToVendorCurrency(
        vendTable.ETGTradeLimitPurchReal, companyCurrency, vendorCurrency);
}

private real convertAmountToVendorCurrency(AmountCur _amount, CurrencyCode _fromCurrency, CurrencyCode _toCurrency)
{
    if (_amount == 0 || !_fromCurrency || !_toCurrency)
    {
        return 0;
    }

    CurrencyExchangeHelper currencyExchangeHelper = CurrencyExchangeHelper::newExchangeDate(
        Ledger::current(), systemDateGet());

    AmountMst convertedAmount = currencyExchangeHelper.calculateCurrencyToCurrency(
        _fromCurrency, _toCurrency, _amount, true);

    return convertedAmount;
}
